UPDATE deployments 
SET estado = 'Error', 
    error_log = '{{ $json.error_message ? $json.error_message.replace(/'/g, "''") : "Error desconocido" }}' 
WHERE id = {{ $json.id }}
RETURNING id, error_log AS error_message, spreadsheet_id, fila_sheets AS row_number;
